const input = $json.body || $json;
const prompt = String(input.prompt || '').trim();
const items = Array.isArray(input.wardrobe_items) ? input.wardrobe_items : [];

if (!prompt) {
  return [{
    json: {
      post_ids: [],
      nombre_outfit: '',
      descripcion: 'Prompt vacio'
    }
  }];
}

if (items.length < 4) {
  return [{
    json: {
      post_ids: [],
      nombre_outfit: '',
      descripcion: 'No hay suficientes prendas en el armario'
    }
  }];
}

const normalizedPrompt = prompt.toLowerCase();

const keywordGroups = [
  { tags: ['navidad', 'cena', 'fiesta', 'noche', 'evento'], weight: 3 },
  { tags: ['elegante', 'formal', 'sofisticado', 'traje', 'blazer', 'vestido'], weight: 3 },
  { tags: ['casual', 'diario', 'streetwear', 'urbano', 'comodo'], weight: 2 },
  { tags: ['invierno', 'frio', 'abrigado', 'lana', 'chaqueta', 'abrigo'], weight: 2 },
  { tags: ['verano', 'calor', 'fresco', 'ligero', 'lino', 'short'], weight: 2 },
  { tags: ['deportivo', 'gym', 'running', 'entreno'], weight: 2 },
  { tags: ['romantico', 'cita', 'date'], weight: 2 },
  { tags: ['trabajo', 'oficina', 'business'], weight: 2 }
];

function scoreItem(item) {
  const text = `${item.pie_foto || ''} ${item.descripcion_prenda || ''}`.toLowerCase();
  let score = 0;

  for (const group of keywordGroups) {
    const promptHasGroup = group.tags.some((tag) => normalizedPrompt.includes(tag));
    if (!promptHasGroup) continue;

    const matches = group.tags.filter((tag) => text.includes(tag)).length;
    score += matches * group.weight;
  }

  // Bonus por riqueza descriptiva para favorecer prendas mejor descritas
  if ((item.descripcion_prenda || '').length > 40) score += 1;

  return score;
}

const ranked = items
  .map((item) => ({ ...item, _score: scoreItem(item) }))
  .sort((a, b) => b._score - a._score);

// Si todo da 0, elegimos las mas recientes como fallback
const allZero = ranked.every((item) => item._score === 0);
const selected = (allZero ? items : ranked).slice(0, 4);

const postIds = selected
  .map((item) => Number(item.post_id))
  .filter((id) => Number.isInteger(id) && id > 0)
  .slice(0, 4);

const nombre = `Outfit IA: ${prompt}`.slice(0, 120);
const descripcion = allZero
  ? 'No habia coincidencias claras por texto; se eligieron prendas recientes del armario.'
  : `Seleccion basada en el prompt: ${prompt}.`;

return [{
  json: {
    post_ids: postIds,
    nombre_outfit: nombre,
    descripcion
  }
}];
